/**
 * Build-time constants injected by Vite/Vitest `define`
 * (see vite.config.ts and vitest.config.ts).
 */
declare const __APP_VERSION__: string;
/** Short git commit of the build, or "dev" when built outside a git checkout. */
declare const __GIT_COMMIT__: string;
/** ISO timestamp of when the bundle was built (dev-server start under `npm run dev`). */
declare const __BUILD_TIME__: string;
